/**
 * Minimal observable store for shared application state.
 * Usage:
 *   import { store } from './store.js'
 *   store.subscribe(state => renderUI(state))
 *   store.set({ user: { name: 'Alice' } })
 */
export function createStore(initialState = {}) {
  let state = { ...initialState }
  const listeners = new Set()

  return {
    get: () => ({ ...state }),
    set(patch) {
      state = { ...state, ...patch }
      listeners.forEach(fn => {
        try {
          fn({ ...state })
        } catch (err) {
          // eslint-disable-next-line no-console
          console.error('[store] subscriber error:', err)
        }
      })
    },
    subscribe(fn) {
      listeners.add(fn)
      return () => listeners.delete(fn)
    },
    reset() {
      state = { ...initialState }
      listeners.clear()
    },
  }
}

/**
 * Async action helper — wraps an async function and manages loading/error state.
 * Usage:
 *   const dispatch = createAsyncAction(store.set.bind(store))
 *   const data = await dispatch(() => fetch('/api/data').then(r => r.json()))
 */
export function createAsyncAction(setState) {
  return async function dispatch(thunk) {
    setState({ loading: true, error: null })
    try {
      const result = await thunk()
      setState({ loading: false, error: null })
      return result
    } catch (err) {
      setState({ loading: false, error: err })
      // Do NOT re-throw — store.error is the contract
      return undefined
    }
  }
}

export const store = createStore({ count: 0, loading: false, error: null })

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest'
import { createStore, createAsyncAction, store } from './store.js'

describe('createStore', () => {
  it('get() returns initial state', () => {
    const s = createStore({ count: 0 })
    expect(s.get()).toEqual({ count: 0 })
  })

  it('set() merges patch into state without clobbering other keys', () => {
    const s = createStore({ count: 0, name: 'test' })
    s.set({ count: 5 })
    expect(s.get()).toEqual({ count: 5, name: 'test' })
  })

  it('subscribe() receives updated state when set() is called', () => {
    const s = createStore({ count: 0 })
    const calls = []
    s.subscribe(state => calls.push(state))
    s.set({ count: 1 })
    expect(calls).toHaveLength(1)
    expect(calls[0]).toEqual({ count: 1 })
  })

  it('subscribe() does not call fn immediately at registration', () => {
    const s = createStore({ count: 42 })
    const calls = []
    s.subscribe(state => calls.push(state))
    // No set() called — fn should not have been invoked yet
    expect(calls).toHaveLength(0)
  })

  it('unsubscribe() stops receiving further updates', () => {
    const s = createStore({ count: 0 })
    const calls = []
    const unsub = s.subscribe(state => calls.push(state))
    s.set({ count: 1 })
    unsub()
    s.set({ count: 2 })
    expect(calls).toHaveLength(1)
    expect(calls[0]).toEqual({ count: 1 })
  })

  it('get() returns a shallow copy (mutations do not affect store)', () => {
    const s = createStore({ count: 0 })
    const state = s.get()
    state.count = 99
    expect(s.get().count).toBe(0)
  })

  it('notifies all active subscribers on each set()', () => {
    const s = createStore({ x: 0 })
    const a = []
    const b = []
    s.subscribe(state => a.push(state.x))
    s.subscribe(state => b.push(state.x))
    s.set({ x: 7 })
    expect(a).toEqual([7])
    expect(b).toEqual([7])
  })

  it('set({}) with empty patch still notifies subscribers with current state', () => {
    const s = createStore({ count: 5 })
    const calls = []
    s.subscribe(state => calls.push(state.count))
    s.set({})
    expect(calls).toHaveLength(1)
    expect(calls[0]).toBe(5)
  })

  it('subscribe() delivers isolated copy — subscriber mutations do not affect store', () => {
    const s = createStore({ count: 0 })
    s.subscribe(state => {
      state.count = 999  // mutate received state
    })
    s.set({ count: 1 })
    expect(s.get().count).toBe(1)  // internal state unaffected
  })

  it('each concurrent subscriber receives an independent state copy', () => {
    const s = createStore({ count: 0 })
    let bReceivedCount = -1

    // Subscriber A: mutates its copy aggressively
    s.subscribe(state => {
      state.count = 999
    })
    // Subscriber B: reads its copy after A has run
    s.subscribe(state => {
      bReceivedCount = state.count
    })

    s.set({ count: 1 })
    expect(bReceivedCount).toBe(1)  // B got the original value, not 999
  })

  it('subscribing the same function twice registers it only once', () => {
    const s = createStore({ count: 0 })
    const calls = []
    const fn = state => calls.push(state.count)
    s.subscribe(fn)
    s.subscribe(fn)  // second subscribe — same reference
    s.set({ count: 1 })
    expect(calls).toHaveLength(1)  // fired only once, not twice
  })

  it('unsubscribing one of two identical subscriptions removes the function entirely', () => {
    const s = createStore({ count: 0 })
    const calls = []
    const fn = state => calls.push(state.count)
    const unsub1 = s.subscribe(fn)
    s.subscribe(fn)
    unsub1()  // removes fn from the Set
    s.set({ count: 1 })
    expect(calls).toHaveLength(0)  // fn no longer in listeners
  })
})

describe('createAsyncAction', () => {
  let s

  beforeEach(() => {
    s = createStore({ loading: false, error: null })
  })

  it('sets loading true during async action', async () => {
    const states = []
    s.subscribe(state => states.push({ ...state }))
    const dispatch = createAsyncAction(s.set.bind(s))
    await dispatch(() => Promise.resolve())
    expect(states[0].loading).toBe(true)
    expect(states[1].loading).toBe(false)
  })

  it('sets error on async action failure', async () => {
    const err = new Error('oops')
    const dispatch = createAsyncAction(s.set.bind(s))
    await dispatch(() => Promise.reject(err))
    expect(s.get().error).toBe(err)
  })

  it('clears error on subsequent successful action', async () => {
    s.set({ error: 'previous error' })
    const dispatch = createAsyncAction(s.set.bind(s))
    await dispatch(() => Promise.resolve())
    expect(s.get().error).toBeNull()
  })

  it('returns the resolved value from the action', async () => {
    const dispatch = createAsyncAction(s.set.bind(s))
    const result = await dispatch(() => Promise.resolve(42))
    expect(result).toBe(42)
  })

  it('does not re-throw on failure — resolves to undefined instead', async () => {
    const dispatch = createAsyncAction(s.set.bind(s))
    const result = await dispatch(() => Promise.reject(new Error('fail')))
    expect(result).toBeUndefined()
    expect(s.get().error).toBeInstanceOf(Error)
    expect(s.get().error.message).toBe('fail')
  })

  it('sets loading:true before thunk and loading:false with error:null after success', async () => {
    const states = []
    const dispatch = createAsyncAction(s.set.bind(s))
    s.subscribe(state => states.push({ ...state }))
    await dispatch(() => Promise.resolve('data'))
    expect(states[0].loading).toBe(true)
    expect(states[0].error).toBeNull()
    expect(states[1].loading).toBe(false)
    expect(states[1].error).toBeNull()
  })

  it('sets error state to the Error object and returns undefined on rejection', async () => {
    const err = new Error('fetch failed')
    const dispatch = createAsyncAction(s.set.bind(s))
    const result = await dispatch(() => Promise.reject(err))
    expect(result).toBeUndefined()
    const state = s.get()
    expect(state.loading).toBe(false)
    expect(state.error).toBe(err)
  })

  it('first dispatch completing resets loading to false while second is still in flight', async () => {
    let resolveFirst
    const firstPromise = new Promise(res => { resolveFirst = res })
    let resolveSecond
    const secondPromise = new Promise(res => { resolveSecond = res })

    const dispatch = createAsyncAction(s.set.bind(s))

    const first = dispatch(() => firstPromise)
    const second = dispatch(() => secondPromise)

    // Both dispatches started — loading should be true
    expect(s.get().loading).toBe(true)

    // First dispatch resolves
    resolveFirst('first result')
    await first

    // After first resolves, loading is false — even though second is still in flight
    expect(s.get().loading).toBe(false)

    // Second dispatch resolves
    resolveSecond('second result')
    await second
    expect(s.get().loading).toBe(false)
  })
})


describe('store (default instance)', () => {
  beforeEach(() => store.reset())

  it('exports a default store with loading and error properties', () => {
    expect(store.get()).toHaveProperty('loading', false)
    expect(store.get()).toHaveProperty('error', null)
  })

  it('exports a default store with a count property', () => {
    expect(store.get()).toHaveProperty('count')
  })
})


describe('reset', () => {
  let s

  beforeEach(() => {
    s = createStore({ count: 0, loading: false, error: null })
  })

  it('clears state set after initialization', () => {
    s.set({ count: 42, extra: 'hello' })
    s.reset()
    const state = s.get()
    expect(state.count).toBe(0)
    expect(state.extra).toBeUndefined()
  })

  it('restores default loading/error fields if present in initial state', () => {
    s.set({ loading: true, error: new Error('oops') })
    s.reset()
    const state = s.get()
    expect(state.loading).toBeFalsy()
    expect(state.error).toBeFalsy()
  })

  it('notifies subscribers after reset', () => {
    // reset() clears listeners without notifying them; a subscriber added
    // after reset() should still receive subsequent set() calls
    const spy = vi.fn()
    s.reset()
    s.subscribe(spy)
    s.set({ count: 1 })
    expect(spy).toHaveBeenCalledOnce()
  })

  it('silently drops subscribers registered before reset()', () => {
    const spy = vi.fn()
    s.subscribe(spy)
    s.reset()
    s.set({ count: 99 })
    expect(spy).not.toHaveBeenCalled()
  })
})
describe('subscribe error isolation', () => {
  beforeEach(() => store.reset())
  afterEach(() => {
    store.reset()
    vi.restoreAllMocks()
  })

  it('continues notifying remaining subscribers if one throws', () => {
    const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})
    const secondCalled = vi.fn()

    store.subscribe(() => { throw new Error('subscriber error') })
    store.subscribe(secondCalled)

    expect(() => store.set({ x: 1 })).not.toThrow()
    expect(secondCalled).toHaveBeenCalled()
    expect(consoleSpy).toHaveBeenCalledOnce()
  })
})

import { describe, it, expect, beforeEach, afterEach } from 'vitest'
import { store } from './store.js'
import { initApp } from './main.js'

/**
 * Helper: build a minimal DOM root that mirrors the structure in index.html
 * without using innerHTML.
 */
function createRoot() {
  const root = document.createElement('div')
  root.id = 'app'

  const counterBtn = document.createElement('button')
  counterBtn.id = 'counterBtn'
  root.appendChild(counterBtn)

  const countSpan = document.createElement('span')
  countSpan.id = 'count'
  root.appendChild(countSpan)

  return root
}

describe('initApp()', () => {
  let root
  let unsub

  beforeEach(() => {
    store.reset()
    root = createRoot()
  })

  afterEach(() => {
    unsub?.()
  })

  it('renders the initial count value from the store into #count', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    expect(countSpan.textContent).toBe('0')
  })

  it('increments the count when the counter button is clicked', () => {
    unsub = initApp(root)
    const counterBtn = root.querySelector('#counterBtn')
    const countSpan = root.querySelector('#count')

    counterBtn.click()
    expect(countSpan.textContent).toBe('1')

    counterBtn.click()
    expect(countSpan.textContent).toBe('2')
  })

  it('shows "..." in #count while the store is in loading state', () => {
    unsub = initApp(root)
    store.set({ loading: true })
    const countSpan = root.querySelector('#count')
    expect(countSpan.textContent).toBe('...')
  })

  it('shows "Error" in #count when the store has an error', () => {
    unsub = initApp(root)
    store.set({ loading: false, error: new Error('boom') })
    const countSpan = root.querySelector('#count')
    expect(countSpan.textContent).toBe('Error')
  })

  it('shows "..." if store is already in loading state when initApp is called', () => {
    store.set({ loading: true })
    unsub = initApp(root)
    expect(root.querySelector('#count').textContent).toBe('...')
  })

  it('shows "Error" if store already has an error when initApp is called', () => {
    store.set({ loading: false, error: new Error('pre-init error') })
    unsub = initApp(root)
    expect(root.querySelector('#count').textContent).toBe('Error')
  })

  it('does not throw when root has no #counterBtn', () => {
    const bareRoot = document.createElement('div')
    const countSpan = document.createElement('span')
    countSpan.id = 'count'
    bareRoot.appendChild(countSpan)
    expect(() => { unsub = initApp(bareRoot) }).not.toThrow()
  })

  it('does not throw when root has no #count span', () => {
    const bareRoot = document.createElement('div')
    const btn = document.createElement('button')
    btn.id = 'counterBtn'
    bareRoot.appendChild(btn)
    expect(() => { unsub = initApp(bareRoot) }).not.toThrow()
  })

  it('unsub stops DOM updates after being called', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    unsub()
    store.set({ count: 99 })
    expect(countSpan.textContent).toBe('0')
  })
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { clamp, formatCurrency, debounce } from './utils.js'

describe('clamp', () => {
  it('returns value when within range', () => {
    expect(clamp(5, 0, 10)).toBe(5)
  })

  it('clamps to minimum', () => {
    expect(clamp(-3, 0, 10)).toBe(0)
  })

  it('clamps to maximum', () => {
    expect(clamp(15, 0, 10)).toBe(10)
  })

  it('clamps to min when min === max', () => {
    expect(clamp(5, 10, 10)).toBe(10)
  })

  it('handles min > max gracefully (does not throw)', () => {
    expect(() => clamp(5, 10, 5)).not.toThrow()
  })
})

describe('formatCurrency', () => {
  it('formats USD by default', () => {
    expect(formatCurrency(1234.5)).toBe('$1,234.50')
  })

  it('formats other currencies', () => {
    expect(formatCurrency(99, 'EUR')).toContain('99')
  })

  it('formats negative amounts', () => {
    const result = formatCurrency(-1.50)
    expect(result).toMatch(/-/)
    expect(result).toContain('1.50')
  })

  it('formats zero', () => {
    expect(formatCurrency(0)).toBe('$0.00')
  })

  it('does not throw on NaN', () => {
    expect(() => formatCurrency(NaN)).not.toThrow()
  })

  it('throws RangeError for invalid currency code', () => {
    expect(() => formatCurrency(100, 'INVALID')).toThrow(RangeError)
  })
})

describe('debounce', () => {
  beforeEach(() => vi.useFakeTimers())
  afterEach(() => vi.useRealTimers())

  it('does not call fn before delay elapses', () => {
    const fn = vi.fn()
    const debounced = debounce(fn, 100)
    debounced()
    vi.advanceTimersByTime(99)
    expect(fn).not.toHaveBeenCalled()
  })

  it('calls fn once after delay', () => {
    const fn = vi.fn()
    const debounced = debounce(fn, 100)
    debounced()
    debounced()
    vi.advanceTimersByTime(100)
    expect(fn).toHaveBeenCalledTimes(1)
  })

  it('passes the latest arguments', () => {
    const fn = vi.fn()
    const debounced = debounce(fn, 100)
    debounced('a')
    debounced('b')
    vi.advanceTimersByTime(100)
    expect(fn).toHaveBeenCalledWith('b')
  })
  it('fires after zero delay', () => {
    const fn = vi.fn()
    const debounced = debounce(fn, 0)
    debounced()
    vi.advanceTimersByTime(0)
    expect(fn).toHaveBeenCalledOnce()
  })

  it('resets the timer on repeated calls', () => {
    const fn = vi.fn()
    const debounced = debounce(fn, 300)

    debounced()
    vi.advanceTimersByTime(200)
    debounced()             // resets the 300ms window
    vi.advanceTimersByTime(299)
    expect(fn).not.toHaveBeenCalled()  // would have fired if timer wasn't reset
    vi.advanceTimersByTime(1)
    expect(fn).toHaveBeenCalledOnce()
  })
})

import { describe, it, expect, beforeEach } from 'vitest'
import { createCard } from './card.js'

beforeEach(() => {
  document.body.innerHTML = ''
})

describe('createCard', () => {
  it('renders title and body text', () => {
    const card = createCard({ title: 'Test', body: 'Body text' })
    expect(card.querySelector('h2').textContent).toBe('Test')
    expect(card.querySelector('p').textContent).toBe('Body text')
  })

  it('does not use innerHTML for title/body (XSS safety)', () => {
    const card = createCard({ title: '<script>alert(1)</script>', body: 'safe' })
    expect(card.innerHTML).not.toContain('<script>')
    expect(card.querySelector('h2').textContent).toBe('<script>alert(1)</script>')
  })

  it('returns a div element', () => {
    const card = createCard({ title: 'A', body: 'B' })
    expect(card.tagName).toBe('DIV')
  })

  it('applies card class to wrapper element', () => {
    const card = createCard({ title: 'A', body: 'B' })
    expect(card.classList.contains('card')).toBe(true)
  })
})

describe('createCard edge cases', () => {
  it('renders empty string when title is omitted', () => {
