/**
 * Clamps a number between a minimum and maximum value.
 * @param {number} value
 * @param {number} min
 * @param {number} max
 * @returns {number}
 */
export function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max)
}

/**
 * Formats a number as a currency string (USD by default).
 * @param {number} amount
 * @param {string} [currency='USD']
 * @returns {string}
 */
export function formatCurrency(amount, currency = 'USD') {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(amount)
}

/**
 * Debounces a function so it only fires after `delay` ms of inactivity.
 * @param {Function} fn
 * @param {number} delay
 * @returns {Function}
 */
export function debounce(fn, delay) {
  let timer
  return (...args) => {
    clearTimeout(timer)
    timer = setTimeout(() => fn(...args), delay)
  }
}

/**
 * Card component factory — returns a DOM element with a title and body.
 * Uses createElement/textContent instead of innerHTML to prevent XSS.
 *
 * @param {{ title: string, body: string }} options
 * @returns {HTMLDivElement}
 */
export function createCard({ title = '', body = '' } = {}) {
  const card = document.createElement('div')
  card.className = 'card'

  const h2 = document.createElement('h2')
  h2.textContent = title ?? ''
  card.appendChild(h2)

  const p = document.createElement('p')
  p.textContent = body ?? ''
  card.appendChild(p)

  return card
}

import { defineConfig } from 'vite'

export default defineConfig(({ command }) => ({
  // Base URL for deployment — override with VITE_BASE_URL env var if needed
  base: process.env.VITE_BASE_URL || '/',

  build: {
    // Warn when chunks exceed 500KB
    chunkSizeWarningLimit: 500,
  },

  server: {
    // Development server port
    port: 5173,
    strictPort: false
  },

  plugins: [
    {
      // Strip ws://localhost:* from CSP in production — only needed for Vite HMR in dev
      name: 'strip-dev-csp',
      transformIndexHtml(html) {
        if (command === 'serve') return html
        return html.replace(/ ws:\/\/localhost:\*/g, '')
      }
    }
  ],

  test: {
    environment: 'jsdom',
    globals: true,
    coverage: {
      provider: 'v8',
      reporter: ['text', 'lcov'],
      include: ['src/**/*.js'],
      exclude: ['src/**/*.test.js'],
      thresholds: {
        statements: 75,
        branches: 70,
        functions: 80,
        lines: 75
      }
    }
  }
}))
